import React from "react";
import UserDashboard from "../components/user/UserDashboard";

export default function UserPortal() {
  return (
    <div className="page">
      <div className="page-header">
        <h1>User Portal</h1>
        <span className="page-pill">For end users</span>
      </div>
      <p className="page-subtitle">
        Connect your wallet, view your reusable KYC credential, and access
        services without repeating verification.
      </p>
      <div className="grid">
        <UserDashboard />
      </div>
    </div>
  );
}
